#include <cuda_runtime.h>
#include <stdio.h>
#include <stdlib.h>
#include <math.h>

#ifndef fp
#define fp float
#endif

#ifndef NUMBER_THREADS
#ifdef RD_WG_SIZE_0_0
#define NUMBER_THREADS RD_WG_SIZE_0_0
#elif defined(RD_WG_SIZE_0)
#define NUMBER_THREADS RD_WG_SIZE_0
#elif defined(RD_WG_SIZE)
#define NUMBER_THREADS RD_WG_SIZE
#else
#define NUMBER_THREADS 256
#endif
#endif

extern "C" int device_id_inuse __attribute__((weak));

static void fatal_cuda(cudaError_t error, int line_no) {
    fprintf(stderr, "CUDA error at line %d: %s\n", line_no, cudaGetErrorString(error));
    exit((int)error);
}

#define CUDA_CHECK(call)                                                          \
    do {                                                                          \
        cudaError_t err__ = (call);                                               \
        if (err__ != cudaSuccess) {                                               \
            fatal_cuda(err__, __LINE__);                                          \
        }                                                                         \
    } while (0)

#define CUDA_CHECK_LAST()                                                         \
    do {                                                                          \
        cudaError_t err__ = cudaGetLastError();                                   \
        if (err__ != cudaSuccess) {                                               \
            fatal_cuda(err__, __LINE__);                                          \
        }                                                                         \
    } while (0)

__global__ void extract(long d_Ne, fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = expf(d_I[ei] / 255.0f);
    }
}

__global__ void prepare(long d_Ne,
                        fp *d_I,
                        fp *d_sums,
                        fp *d_sums2) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_sums[ei] = d_I[ei];
        d_sums2[ei] = d_I[ei] * d_I[ei];
    }
}

__global__ void reduce(long d_Ne,
                       long d_no,
                       int d_mul,
                       fp *d_sums,
                       fp *d_sums2) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    int nf = NUMBER_THREADS - (gridDim.x * NUMBER_THREADS - (int)d_no);
    int df = 0;

    __shared__ fp d_psum[NUMBER_THREADS];
    __shared__ fp d_psum2[NUMBER_THREADS];

    int i;

    if (ei < d_no) {
        d_psum[tx] = d_sums[ei * d_mul];
        d_psum2[tx] = d_sums2[ei * d_mul];
    }

    __syncthreads();

    if (nf == NUMBER_THREADS) {
        for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
            if ((tx + 1) % i == 0) {
                d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
            }
            __syncthreads();
        }

        if (tx == (NUMBER_THREADS - 1)) {
            d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
            d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
        }
    } else {
        if (bx != (gridDim.x - 1)) {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if ((tx + 1) % i == 0) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                __syncthreads();
            }

            if (tx == (NUMBER_THREADS - 1)) {
                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        } else {
            for (i = 2; i <= NUMBER_THREADS; i = 2 * i) {
                if (nf >= i) {
                    df = i;
                }
            }

            for (i = 2; i <= df; i = 2 * i) {
                if ((tx + 1) % i == 0 && tx < df) {
                    d_psum[tx] = d_psum[tx] + d_psum[tx - i / 2];
                    d_psum2[tx] = d_psum2[tx] + d_psum2[tx - i / 2];
                }
                __syncthreads();
            }

            if (tx == (df - 1)) {
                for (i = (bx * NUMBER_THREADS) + df; i < (bx * NUMBER_THREADS) + nf; i++) {
                    d_psum[tx] = d_psum[tx] + d_sums[i];
                    d_psum2[tx] = d_psum2[tx] + d_sums2[i];
                }

                d_sums[bx * d_mul * NUMBER_THREADS] = d_psum[tx];
                d_sums2[bx * d_mul * NUMBER_THREADS] = d_psum2[tx];
            }
        }
    }

    (void)d_Ne;
}

__global__ void srad(fp d_lambda,
                     int d_Nr,
                     int d_Nc,
                     long d_Ne,
                     int *d_iN,
                     int *d_iS,
                     int *d_jE,
                     int *d_jW,
                     fp *d_dN,
                     fp *d_dS,
                     fp *d_dE,
                     fp *d_dW,
                     fp d_q0sqr,
                     fp *d_c,
                     fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = bx * NUMBER_THREADS + tx;
    int row;
    int col;

    fp d_Jc;
    fp d_dN_loc, d_dS_loc, d_dW_loc, d_dE_loc;
    fp d_c_loc;
    fp d_G2, d_L, d_num, d_den, d_qsqr;

    row = (ei + 1) % d_Nr - 1;
    col = (ei + 1) / d_Nr + 1 - 1;
    if ((ei + 1) % d_Nr == 0) {
        row = d_Nr - 1;
        col = col - 1;
    }

    if (ei < d_Ne) {
        d_Jc = d_I[ei];

        d_dN_loc = d_I[d_iN[row] + d_Nr * col] - d_Jc;
        d_dS_loc = d_I[d_iS[row] + d_Nr * col] - d_Jc;
        d_dW_loc = d_I[row + d_Nr * d_jW[col]] - d_Jc;
        d_dE_loc = d_I[row + d_Nr * d_jE[col]] - d_Jc;

        d_G2 = (d_dN_loc * d_dN_loc + d_dS_loc * d_dS_loc +
                d_dW_loc * d_dW_loc + d_dE_loc * d_dE_loc) /
               (d_Jc * d_Jc);

        d_L = (d_dN_loc + d_dS_loc + d_dW_loc + d_dE_loc) / d_Jc;

        d_num = (0.5f * d_G2) - ((1.0f / 16.0f) * (d_L * d_L));
        d_den = 1.0f + (0.25f * d_L);
        d_qsqr = d_num / (d_den * d_den);

        d_den = (d_qsqr - d_q0sqr) / (d_q0sqr * (1.0f + d_q0sqr));
        d_c_loc = 1.0f / (1.0f + d_den);

        if (d_c_loc < 0.0f) {
            d_c_loc = 0.0f;
        } else if (d_c_loc > 1.0f) {
            d_c_loc = 1.0f;
        }

        d_dN[ei] = d_dN_loc;
        d_dS[ei] = d_dS_loc;
        d_dW[ei] = d_dW_loc;
        d_dE[ei] = d_dE_loc;
        d_c[ei] = d_c_loc;
    }

    (void)d_lambda;
    (void)d_Nc;
}

__global__ void srad2(fp d_lambda,
                      int d_Nr,
                      int d_Nc,
                      long d_Ne,
                      int *d_iN,
                      int *d_iS,
                      int *d_jE,
                      int *d_jW,
                      fp *d_dN,
                      fp *d_dS,
                      fp *d_dE,
                      fp *d_dW,
                      fp *d_c,
                      fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = bx * NUMBER_THREADS + tx;
    int row;
    int col;

    fp d_cN, d_cS, d_cW, d_cE;
    fp d_D;

    row = (ei + 1) % d_Nr - 1;
    col = (ei + 1) / d_Nr + 1 - 1;
    if ((ei + 1) % d_Nr == 0) {
        row = d_Nr - 1;
        col = col - 1;
    }

    if (ei < d_Ne) {
        d_cN = d_c[ei];
        d_cS = d_c[d_iS[row] + d_Nr * col];
        d_cW = d_c[ei];
        d_cE = d_c[row + d_Nr * d_jE[col]];

        d_D = d_cN * d_dN[ei] + d_cS * d_dS[ei] + d_cW * d_dW[ei] + d_cE * d_dE[ei];

        d_I[ei] = d_I[ei] + 0.25f * d_lambda * d_D;
    }

    (void)d_Nc;
    (void)d_jW;
}

__global__ void compress(long d_Ne, fp *d_I) {
    int bx = blockIdx.x;
    int tx = threadIdx.x;
    int ei = (bx * NUMBER_THREADS) + tx;

    if (ei < d_Ne) {
        d_I[ei] = logf(d_I[ei]) * 255.0f;
    }
}

static void kernel_gpu_cuda_wrapper_impl(fp *image,
                                         int Nr,
                                         int Nc,
                                         long Ne,
                                         int niter,
                                         fp lambda,
                                         long NeROI,
                                         int *iN,
                                         int *iS,
                                         int *jE,
                                         int *jW,
                                         int iter,
                                         int mem_size_i,
                                         int mem_size_j) {
    int device_count = 0;
    CUDA_CHECK(cudaGetDeviceCount(&device_count));
    if (device_count <= 0) {
        fprintf(stderr, "Error: no CUDA devices found\n");
        exit(1);
    }

    int dev = 0;
#if defined(__GNUC__)
    if (&device_id_inuse) {
        dev = device_id_inuse;
    }
#endif
    if (dev < 0 || dev >= device_count) {
        dev = 0;
    }

    CUDA_CHECK(cudaSetDevice(dev));

    cudaDeviceProp prop;
    CUDA_CHECK(cudaGetDeviceProperties(&prop, dev));

    printf("Platform: CUDA\n");
    printf("Device: %s\n", prop.name);
    printf("-----OpenCL Compiler Output-----\n");
    printf("--------------------------------\n");

    int blocks_x = (int)(Ne / (long)NUMBER_THREADS);
    if (Ne % (long)NUMBER_THREADS != 0) {
        blocks_x = blocks_x + 1;
    }

    printf("max # of workgroups = %d, # of threads/workgroup = %d (ensure that device can handle)\n",
           blocks_x, NUMBER_THREADS);

    size_t mem_size = sizeof(fp) * (size_t)Ne;
    int mem_size_single = (int)sizeof(fp);

    fp *d_I = NULL;
    int *d_iN = NULL;
    int *d_iS = NULL;
    int *d_jE = NULL;
    int *d_jW = NULL;
    fp *d_dN = NULL;
    fp *d_dS = NULL;
    fp *d_dW = NULL;
    fp *d_dE = NULL;
    fp *d_c = NULL;
    fp *d_sums = NULL;
    fp *d_sums2 = NULL;

    CUDA_CHECK(cudaMalloc((void **)&d_I, mem_size));

    CUDA_CHECK(cudaMalloc((void **)&d_iN, (size_t)mem_size_i));
    CUDA_CHECK(cudaMalloc((void **)&d_iS, (size_t)mem_size_i));
    CUDA_CHECK(cudaMalloc((void **)&d_jE, (size_t)mem_size_j));
    CUDA_CHECK(cudaMalloc((void **)&d_jW, (size_t)mem_size_j));

    CUDA_CHECK(cudaMalloc((void **)&d_dN, mem_size));
    CUDA_CHECK(cudaMalloc((void **)&d_dS, mem_size));
    CUDA_CHECK(cudaMalloc((void **)&d_dW, mem_size));
    CUDA_CHECK(cudaMalloc((void **)&d_dE, mem_size));

    CUDA_CHECK(cudaMalloc((void **)&d_c, mem_size));

    CUDA_CHECK(cudaMalloc((void **)&d_sums, mem_size));
    CUDA_CHECK(cudaMalloc((void **)&d_sums2, mem_size));

    CUDA_CHECK(cudaMemcpy(d_I, image, mem_size, cudaMemcpyHostToDevice));

    CUDA_CHECK(cudaMemcpy(d_iN, iN, (size_t)mem_size_i, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_iS, iS, (size_t)mem_size_i, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_jE, jE, (size_t)mem_size_j, cudaMemcpyHostToDevice));
    CUDA_CHECK(cudaMemcpy(d_jW, jW, (size_t)mem_size_j, cudaMemcpyHostToDevice));

    extract<<<blocks_x, NUMBER_THREADS>>>(Ne, d_I);
    CUDA_CHECK_LAST();

    fp total;
    fp total2;
    fp meanROI;
    fp meanROI2;
    fp varROI;
    fp q0sqr;

    printf("Iterations Progress: hidden");

    for (iter = 0; iter < niter; iter++) {
        fflush(NULL);

        prepare<<<blocks_x, NUMBER_THREADS>>>(Ne, d_I, d_sums, d_sums2);
        CUDA_CHECK_LAST();

        int blocks2_work_size = blocks_x;
        long no = Ne;
        int mul = 1;

        while (blocks2_work_size != 0) {
            reduce<<<blocks2_work_size, NUMBER_THREADS>>>(Ne, no, mul, d_sums, d_sums2);
            CUDA_CHECK_LAST();

            no = blocks2_work_size;
            if (blocks2_work_size == 1) {
                blocks2_work_size = 0;
            } else {
                mul = mul * NUMBER_THREADS;
                blocks2_work_size = blocks2_work_size / NUMBER_THREADS;
                if (no % NUMBER_THREADS != 0) {
                    blocks2_work_size = blocks2_work_size + 1;
                }
            }
        }

        CUDA_CHECK(cudaMemcpy(&total, d_sums, (size_t)mem_size_single, cudaMemcpyDeviceToHost));
        CUDA_CHECK(cudaMemcpy(&total2, d_sums2, (size_t)mem_size_single, cudaMemcpyDeviceToHost));

        meanROI = total / (fp)(NeROI);
        meanROI2 = meanROI * meanROI;
        varROI = (total2 / (fp)(NeROI)) - meanROI2;
        q0sqr = varROI / meanROI2;

        srad<<<blocks_x, NUMBER_THREADS>>>(lambda, Nr, Nc, Ne,
                                           d_iN, d_iS, d_jE, d_jW,
                                           d_dN, d_dS, d_dE, d_dW,
                                           q0sqr, d_c, d_I);
        CUDA_CHECK_LAST();

        srad2<<<blocks_x, NUMBER_THREADS>>>(lambda, Nr, Nc, Ne,
                                            d_iN, d_iS, d_jE, d_jW,
                                            d_dN, d_dS, d_dE, d_dW,
                                            d_c, d_I);
        CUDA_CHECK_LAST();
    }

    printf("\n");

    compress<<<blocks_x, NUMBER_THREADS>>>(Ne, d_I);
    CUDA_CHECK_LAST();

    CUDA_CHECK(cudaMemcpy(image, d_I, mem_size, cudaMemcpyDeviceToHost));

    CUDA_CHECK(cudaFree(d_I));
    CUDA_CHECK(cudaFree(d_c));

    CUDA_CHECK(cudaFree(d_iN));
    CUDA_CHECK(cudaFree(d_iS));
    CUDA_CHECK(cudaFree(d_jE));
    CUDA_CHECK(cudaFree(d_jW));

    CUDA_CHECK(cudaFree(d_dN));
    CUDA_CHECK(cudaFree(d_dS));
    CUDA_CHECK(cudaFree(d_dE));
    CUDA_CHECK(cudaFree(d_dW));

    CUDA_CHECK(cudaFree(d_sums));
    CUDA_CHECK(cudaFree(d_sums2));
}

